import{_ as s,c as a,o as n,a as e}from"./app.204b65b3.js";const y=JSON.parse('{"title":".gitignore 忽略文件的用法","description":"","frontmatter":{},"headers":[{"level":2,"title":"1.Git 忽略文件 .gitignore 详解","slug":"_1-git-忽略文件-gitignore-详解","link":"#_1-git-忽略文件-gitignore-详解","children":[]},{"level":2,"title":"2.忽略语法","slug":"_2-忽略语法","link":"#_2-忽略语法","children":[]},{"level":2,"title":"3.已被推送过的文件","slug":"_3-已被推送过的文件","link":"#_3-已被推送过的文件","children":[]},{"level":2,"title":"4.参考链接","slug":"_4-参考链接","link":"#_4-参考链接","children":[]}],"relativePath":"articles/04-其他/Git/05-gitignore忽略文件的用法.md"}'),l={name:"articles/04-其他/Git/05-gitignore忽略文件的用法.md"},p=e(`<h1 id="gitignore-忽略文件的用法" tabindex="-1">.gitignore 忽略文件的用法 <a class="header-anchor" href="#gitignore-忽略文件的用法" aria-hidden="true">#</a></h1><h2 id="_1-git-忽略文件-gitignore-详解" tabindex="-1">1.Git 忽略文件 <code>.gitignore</code> 详解 <a class="header-anchor" href="#_1-git-忽略文件-gitignore-详解" aria-hidden="true">#</a></h2><p>在工程中，并不是所有文件都需要保存到版本库中的，例如<code>dist</code>目录及目录下的文件就可以忽略。在 <code>Git</code> 工作区的根目录下创建一个特殊的 <code>.gitignore</code> 文件，然后把要忽略的文件名填进去，<code>Git</code> 就会自动忽略这些文件或目录。</p><h2 id="_2-忽略语法" tabindex="-1">2.忽略语法 <a class="header-anchor" href="#_2-忽略语法" aria-hidden="true">#</a></h2><p>1.注释使用#开头，后面跟注释内容</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 注释</span></span>
<span class="line"></span></code></pre></div><p>2.! 开头的模式表示反向操作，该文件将会再次被包含，如果忽略了该文件的父级目录，则使用 ! 也不会使该文件再次被包含</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">!</span><span style="color:#FFCB6B;">/bin/run.sh</span><span style="color:#A6ACCD;">    </span><span style="color:#C3E88D;">表示不忽略bin目录下的run.sh文件</span></span>
<span class="line"></span></code></pre></div><p>3./ 结束的模式只匹配文件夹以及在该文件夹路径下的内容，但是不匹配该文件</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">build/</span><span style="color:#A6ACCD;">          </span><span style="color:#C3E88D;">表示忽略</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">build/目录下的所有文件，过滤整个build文件夹</span></span>
<span class="line"></span></code></pre></div><p>4./ 开始的模式匹配项目根目录</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">/TODO</span><span style="color:#A6ACCD;">           </span><span style="color:#C3E88D;">表示仅仅忽略项目根目录下的</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">TODO</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">文件，不包括</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">subdir/TODO</span></span>
<span class="line"></span></code></pre></div><p>5.如果一个模式不包含斜杠，则它匹配相对于当前 .gitignore 文件路径的内容（目录和文件），如果该模式不在 .gitignore 文件中，则相对于项目根目录</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">config.php:</span><span style="color:#A6ACCD;">     </span><span style="color:#C3E88D;">表示忽略当前路径的</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">config.php</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">文件</span></span>
<span class="line"></span></code></pre></div><p>6.** 匹配多级目录，可在开始，中间，结束</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">**</span><span style="color:#A6ACCD;">/foo:         表示忽略/foo,a/foo,a/b/foo等</span></span>
<span class="line"><span style="color:#FFCB6B;">a/**/b:</span><span style="color:#A6ACCD;">         </span><span style="color:#C3E88D;">表示忽略a/b,</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">a/x/b,a/x/y/b等</span></span>
<span class="line"></span></code></pre></div><p>7.? 通用匹配单个字符</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#89DDFF;">?</span><span style="color:#A6ACCD;">.log.    表示忽略所有 1.log 文件</span></span>
<span class="line"></span></code></pre></div><p>8.* 通用匹配零个或多个字符</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">doc/*.txt</span><span style="color:#A6ACCD;">       </span><span style="color:#C3E88D;">表示会忽略doc/notes.txt但不包括</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">doc/server/arch.txt</span></span>
<span class="line"><span style="color:#FFCB6B;">/*.c:</span><span style="color:#A6ACCD;">           </span><span style="color:#C3E88D;">表示忽略cat.c，不忽略</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">build/cat.c</span></span>
<span class="line"><span style="color:#89DDFF;">*</span><span style="color:#A6ACCD;">.log:          表示忽略所有 .log 文件</span></span>
<span class="line"></span></code></pre></div><p>9.[] 通用匹配单个字符列表</p><h2 id="_3-已被推送过的文件" tabindex="-1">3.已被推送过的文件 <a class="header-anchor" href="#_3-已被推送过的文件" aria-hidden="true">#</a></h2><p>已经推送（push）过的文件，在.gitignore 文件内添加是无效的。可以使用以下命令进行强制忽略。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">update-index</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--assume-unchanged</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">文件路径</span></span>
<span class="line"></span></code></pre></div><p>取消强制忽略：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">git</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">update-index</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--no-assume-unchanged</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">文件路径</span></span>
<span class="line"></span></code></pre></div><h2 id="_4-参考链接" tabindex="-1">4.参考链接 <a class="header-anchor" href="#_4-参考链接" aria-hidden="true">#</a></h2><ul><li><p><a href="https://www.cnblogs.com/kevingrace/p/5690241.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/kevingrace/p/5690241.html</a></p></li><li><p><a href="https://blog.csdn.net/fox9916/article/details/127924115" target="_blank" rel="noreferrer">https://blog.csdn.net/fox9916/article/details/127924115</a></p></li></ul>`,28),o=[p];function t(c,i,r,d,h,C){return n(),a("div",null,o)}const b=s(l,[["render",t]]);export{y as __pageData,b as default};
